"""
Parameterized generator for GH950_sktime_2375.

Source PR:    https://github.com/sktime/sktime/pull/2375
Source Issue: N/A

Seed varies: renames 'always' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH950_sktime_2375'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH950_sktime_2375'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('always', 'always' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH950_sktime_2375',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'sktime/sktime',
                "pr_number": 2375,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/sktime/sktime/pull/2375",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'sktime/datatypes/_panel/_convert.py': '# -*- coding: utf-8 -*-\n"""Machine type converters for Panel scitype.\n\nExports conversion and mtype dictionary for Panel scitype:\n\nconvert_dict: dict indexed by triples of str\n  1st element = convert from - str\n  2nd element = convert to - str\n  3rd element = considered as this scitype - str\nelements are conversion functions of machine type (1st) -> 2nd\n\nFunction signature of all elements\nconvert_dict[(from_type, to_type, as_scitype)]\n\nParameters\n----------\nobj : from_type - object to convert\nstore : dictionary - reference of storage for lossy conversions, default=None (no store)\n\nReturns\n-------\nconverted_obj : to_type - object obj converted to to_type\n\nRaises\n------\nValueError and TypeError, if requested conversion is not possible\n                            (depending on conversion logic)\n"""\n\nimport numpy as np\nimport pandas as pd\n\n__all__ = [\n    "convert_dict",\n]\n\nfrom sktime.datatypes._panel._registry import MTYPE_LIST_PANEL\n\n# dictionary indexed by triples of types\n#  1st element = convert from - type\n#  2nd element = convert to - type\n#  3rd element = considered as this scitype - string\n# elements are conversion functions of machine type (1st) -> 2nd\n\nconvert_dict = dict()\n\n\ndef convert_identity(obj, store=None):\n\n    return obj\n\n\n# assign identity function to type conversion to self\nfor tp in MTYPE_LIST_PANEL:\n    convert_dict[(tp, tp, "Panel")] = convert_identity\n\n\ndef _cell_is_series_or_array(cell):\n    return isinstance(cell, (pd.Series, np.ndarray))\n\n\ndef _nested_cell_mask(X):\n    return X.applymap(_cell_is_series_or_array)\n\n\ndef are_columns_nested(X):\n    """Check whether any cells have nested structure in each DataFrame column.\n\n    Parameters\n    ----------\n    X : pd.DataFrame\n        DataFrame to check for nested data structures.\n\n    Returns\n    -------\n    any_nested : bool\n        If True, at least one column is nested.\n        If False, no nested columns.\n    """\n    any_nested = _nested_cell_mask(X).any().values\n    return any_nested\n\n\ndef _nested_cell_timepoints(cell):\n    if _cell_is_series_or_array(cell):\n        n_timepoints = cell.shape[0]\n    else:\n        n_timepoints = 0\n    return n_timepoints\n\n\ndef _check_equal_index(X):\n    """Check if all time-series in nested pandas DataFrame have the same index.\n\n    Parameters\n    ----------\n    X : nested pd.DataFrame\n        Input dataframe with time-series in cells.\n\n    Returns\n    -------\n    indexes : list of indixes\n        List of indixes with one index for each column\n    """\n    # TODO handle 1d series, not only 2d dataframes\n    # TODO assumes columns are typed (i.e. all rows for a given column have\n    #  the same type)\n    # TODO only handles series columns, raises error for columns with\n    #  primitives\n\n    indexes = []\n    # Check index for each column separately.\n    for c, col in enumerate(X.columns):\n\n        # Get index from first row, can be either pd.Series or np.array.\n        first_index = (\n            X.iloc[0, c].index\n            if hasattr(X.iloc[0, c], "index")\n            else np.arange(X.iloc[c, 0].shape[0])\n        )\n\n        # Series must contain at least 2 observations, otherwise should be\n        # primitive.\n        if len(first_index) < 2:\n            raise ValueError(\n                f"Time series must contain at least 2 observations, "\n                f"but found: "\n                f"{len(first_index)} observations in column: {col}"\n            )\n\n        # Check index for all rows.\n        for i in range(1, X.shape[0]):\n            index = (\n                X.iloc[i, c].index\n                if hasattr(X.iloc[i, c], "index")\n                else np.arange(X.iloc[c, 0].shape[0])\n            )\n            if not np.array_equal(first_index, index):\n                raise ValueError(\n                    f"Found time series with unequal index in column {col}. "\n                    f"Input time-series must have the same index."\n                )\n        indexes.append(first_index)\n\n    return indexes\n\n\ndef from_3d_numpy_to_2d_array(X):\n    """Convert 2D NumPy Panel to 2D numpy Panel.\n\n    Converts 3D numpy array (n_instances, n_columns, n_timepoints) to\n    a 2D numpy array with shape (n_instances, n_columns*n_timepoints)\n\n    Parameters\n    ----------\n    X : np.ndarray\n        The input 3d-NumPy array with shape\n        (n_instances, n_columns, n_timepoints)\n\n    Returns\n    -------\n    array_2d : np.ndarray\n        A 2d-NumPy array with shape (n_instances, n_columns*n_timepoints)\n    """\n    array_2d = X.reshape(X.shape[0], -1)\n    return array_2d\n\n\ndef from_3d_numpy_to_2d_array_adp(obj, store=None):\n\n    return from_3d_numpy_to_2d_array(obj)\n\n\nconvert_dict[("numpy3D", "numpyflat", "Panel")] = from_3d_numpy_to_2d_array_adp\n\n\ndef from_nested_to_2d_array(X, return_numpy=False):\n    """Convert nested Panel to 2D numpy Panel.\n\n    Convert nested pandas DataFrame or Series with NumPy arrays or\n    pandas Series in cells into tabular\n    pandas DataFrame with primitives in cells, i.e. a data frame with the\n    same number of rows as the input data and\n    as many columns as there are observations in the nested series. Requires\n    series to be have the same index.\n\n    Parameters\n    ----------\n    X : nested pd.DataFrame or nested pd.Series\n    return_numpy : bool, default = False\n        - If True, returns a NumPy array of the tabular data.\n        - If False, returns a pandas DataFrame with row and column names.\n\n    Returns\n    -------\n     Xt : pandas DataFrame\n        Transformed DataFrame in tabular format\n    """\n    # TODO does not handle dataframes with nested series columns *and*\n    #  standard columns containing only primitives\n\n    # convert nested data into tabular data\n    if isinstance(X, pd.Series):\n        Xt = np.array(X.tolist())\n\n    elif isinstance(X, pd.DataFrame):\n        try:\n            Xt = np.hstack([X.iloc[:, i].tolist() for i in range(X.shape[1])])\n\n        # except strange key error for specific case\n        except KeyError:\n            if (X.shape == (1, 1)) and (X.iloc[0, 0].shape == (1,)):\n                # in fact only breaks when an additional condition is met,\n                # namely that the index of the time series of a single value\n                # does not start with 0, e.g. pd.RangeIndex(9, 10) as is the\n                # case in forecasting\n                Xt = X.iloc[0, 0].values\n            else:\n                raise\n\n        if Xt.ndim != 2:\n            raise ValueError(\n                "Tabularization failed, it\'s possible that not "\n                "all series were of equal length"\n            )\n\n    else:\n        raise ValueError(\n            f"Expected input is pandas Series or pandas DataFrame, "\n            f"but found: {type(X)}"\n        )\n\n    if return_numpy:\n        return Xt\n\n    Xt = pd.DataFrame(Xt)\n\n    # create column names from time index\n    if X.ndim == 1:\n        time_index = (\n            X.iloc[0].index\n            if hasattr(X.iloc[0], "index")\n            else np.arange(X.iloc[0].shape[0])\n        )\n        columns = [f"{X.name}__{i}" for i in time_index]\n\n    else:\n        columns = []\n        for colname, col in X.items():\n            time_index = (\n                col.iloc[0].index\n                if hasattr(col.iloc[0], "index")\n                else np.arange(col.iloc[0].shape[0])\n            )\n            columns.extend([f"{colname}__{i}" for i in time_index])\n\n    Xt.index = X.index\n    Xt.columns = columns\n    return Xt\n\n\ndef from_nested_to_pdwide(obj, store=None):\n\n    return from_nested_to_2d_array(X=obj, return_numpy=False)\n\n\ndef from_nested_to_2d_np_array(obj, store=None):\n\n    return from_nested_to_2d_array(X=obj, return_numpy=True)\n\n\nconvert_dict[("nested_univ", "pd-wide", "Panel")] = from_nested_to_pdwide\n\nconvert_dict[("nested_univ", "numpyflat", "Panel")] = from_nested_to_2d_np_array\n\n\ndef from_2d_array_to_nested(\n    X, index=None, columns=None, time_index=None, cells_as_numpy=False\n):\n    """Convert 2D dataframe to nested dataframe.\n\n    Convert tabular pandas DataFrame with only primitives in cells into\n    nested pandas DataFrame with a single column.\n\n    Parameters\n    ----------\n    X : pd.DataFrame\n\n    cells_as_numpy : bool, default = False\n        If True, then nested cells contain NumPy array\n        If False, then nested cells contain pandas Series\n\n    index : array-like, shape=[n_samples], optional (default = None)\n        Sample (row) index of transformed DataFrame\n\n    time_index : array-like, shape=[n_obs], optional (default = None)\n        Time series index of transformed DataFrame\n\n    Returns\n    -------\n    Xt : pd.DataFrame\n        Transformed DataFrame in nested format\n    """\n    if (time_index is not None) and cells_as_numpy:\n        raise ValueError(\n            "`Time_index` cannot be specified when `return_arrays` is True, "\n            "time index can only be set to "\n            "pandas Series"\n        )\n    if isinstance(X, pd.DataFrame):\n        X = X.to_numpy()\n\n    container = np.array if cells_as_numpy else pd.Series\n\n    # for 2d numpy array, rows represent instances, columns represent time points\n    n_instances, n_timepoints = X.shape\n\n    if time_index is None:\n        time_index = np.arange(n_timepoints)\n    kwargs = {"index": time_index}\n\n    Xt = pd.DataFrame(\n        pd.Series([container(X[i, :], **kwargs) for i in range(n_instances)])\n    )\n    if index is not None:\n        Xt.index = index\n    if columns is not None:\n        Xt.columns = columns\n    return Xt\n\n\ndef from_pd_wide_to_nested(obj, store=None):\n\n    return from_2d_array_to_nested(X=obj)\n\n\nconvert_dict[("pd-wide", "nested_univ", "Panel")] = from_pd_wide_to_nested\n\n\ndef convert_from_dictionary(ts_dict):\n    """Conversion from dictionary to pandas.\n\n    Simple conversion from a dictionary of each series, e.g. univariate\n        x = {\n            "Series1": [1.0,2.0,3.0,1.0,2.0],\n            "Series2": [3.0,2.0,1.0,3.0,2.0],\n        }\n    or multivariate, e.g.\n    to sktime pandas format\n    TODO: Adapt for multivariate\n    """\n    panda = pd.DataFrame(ts_dict)\n    panda = panda.transpose()\n    return from_2d_array_to_nested(panda)\n\n\ndef _concat_nested_arrays(arrs, cells_as_numpy=False):\n    """Nest tabular arrays from nested list.\n\n    Helper function to nest tabular arrays from nested list of arrays.\n\n    Parameters\n    ----------\n    arrs : list of numpy arrays\n        Arrays must have the same number of rows, but can have varying\n        number of columns.\n\n    cells_as_numpy : bool, default = False\n        If True, then nested cells contain NumPy array\n        If False, then nested cells contain pandas Series\n\n    Returns\n    -------\n    Xt : pandas DataFrame\n        Transformed dataframe with nested column for each input array.\n    """\n    if cells_as_numpy:\n        Xt = pd.DataFrame(\n            np.column_stack(\n                [pd.Series([np.array(vals) for vals in interval]) for interval in arrs]\n            )\n        )\n    else:\n        Xt = pd.DataFrame(\n            np.column_stack(\n                [pd.Series([pd.Series(vals) for vals in interval]) for interval in arrs]\n            )\n        )\n    return Xt\n\n\ndef _get_index(x):\n    if hasattr(x, "index"):\n        return x.index\n    else:\n        # select last dimension for time index\n        return pd.RangeIndex(x.shape[-1])\n\n\ndef _get_time_index(X):\n    """Get index of time series data, helper function.\n\n    Parameters\n    ----------\n    X : pd.DataFrame\n\n    Returns\n    -------\n    time_index : pandas Index\n        Index of time series\n    """\n    # assumes that all samples share the same the time index, only looks at\n    # first row\n    if isinstance(X, pd.DataFrame):\n        return _get_index(X.iloc[0, 0])\n\n    elif isinstance(X, pd.Series):\n        return _get_index(X.iloc[0])\n\n    elif isinstance(X, np.ndarray):\n        return _get_index(X)\n\n    else:\n        raise ValueError(\n            f"X must be a pandas DataFrame or Series, but found: {type(X)}"\n        )\n\n\ndef _make_column_names(column_count):\n    return [f"var_{i}" for i in range(column_count)]\n\n\ndef _get_column_names(X):\n    if isinstance(X, pd.DataFrame):\n        return X.columns\n    else:\n        return _make_column_names(X.shape[1])\n\n\ndef from_nested_to_long(\n    X, instance_column_name=None, time_column_name=None, dimension_column_name=None\n):\n    """Convert nested DataFrame to long DataFrame.\n\n    Parameters\n    ----------\n    X : pd.DataFrame\n        The nested DataFrame\n\n    instance_column_name : str\n        The name of column corresponding to the DataFrame\'s instances\n\n    time_column_name : str\n        The name of the column corresponding to the DataFrame\'s timepoints.\n\n    dimension_column_name : str\n        The name of the column corresponding to the DataFrame\'s dimensions.\n\n    Returns\n    -------\n    long_df : pd.DataFrame\n        Long pandas DataFrame\n    """\n    long_df = from_nested_to_multi_index(\n        X, instance_index="index", time_index="time_index"\n    )\n    long_df.reset_index(inplace=True)\n    long_df = long_df.melt(id_vars=["index", "time_index"], var_name="column")\n\n    col_rename_dict = {}\n    if instance_column_name is not None:\n        col_rename_dict["index"] = instance_column_name\n\n    if time_column_name is not None:\n        col_rename_dict["time_index"] = time_column_name\n\n    if dimension_column_name is not None:\n        col_rename_dict["column"] = dimension_column_name\n\n    if len(col_rename_dict) > 0:\n        long_df = long_df.rename(columns=col_rename_dict)\n\n    return long_df\n\n\ndef from_nested_to_long_adp(obj, store=None):\n\n    return from_nested_to_long(\n        X=obj,\n        instance_column_name="case_id",\n        time_column_name="reading_id",\n        dimension_column_name="dim_id",\n    )\n\n\nconvert_dict[("nested_univ", "pd-long", "Panel")] = from_nested_to_long_adp\n\n\ndef from_long_to_nested(\n    X_long,\n    instance_column_name="case_id",\n    time_column_name="reading_id",\n    dimension_column_name="dim_id",\n    value_column_name="value",\n    column_names=None,\n):\n    """Convert long DataFrame to a nested DataFrame.\n\n    Parameters\n    ----------\n    X_long : pd.DataFrame\n        The long DataFrame\n\n    instance_column_name : str, default = \'case_id\'\n        The name of column corresponding to the DataFrame\'s instances.\n\n    time_column_name : str, default = \'reading_id\'\n        The name of the column corresponding to the DataFrame\'s timepoints.\n\n    dimension_column_name : str, default = \'dim_id\'\n        The name of the column corresponding to the DataFrame\'s dimensions.\n\n    value_column_name : str, default = \'value\'\n        The name of the column corresponding to the DataFrame\'s values.\n\n    column_names : list, optional\n        Optional list of column names to use for nested DataFrame columns.\n\n    Returns\n    -------\n    X_nested : pd.DataFrame\n        Nested pandas DataFrame\n    """\n    X_nested = X_long.pivot(\n        index=[instance_column_name, time_column_name],\n        columns=dimension_column_name,\n        values=value_column_name,\n    )\n    X_nested = from_multi_index_to_nested(X_nested, instance_index=instance_column_name)\n\n    n_columns = X_nested.shape[1]\n    if column_names is None:\n        X_nested.columns = _make_column_names(n_columns)\n\n    else:\n        X_nested.columns = column_names\n\n    return X_nested\n\n\ndef from_long_to_nested_adp(obj, store=None):\n\n    return from_long_to_nested(X_long=obj)\n\n\nconvert_dict[("pd-long", "nested_univ", "Panel")] = from_nested_to_long_adp\n\n\ndef from_multi_index_to_3d_numpy(X):\n    """Convert pandas multi-index Panel to numpy 3D Panel.\n\n    Convert panel data stored as pandas multi-index DataFrame to\n    Numpy 3-dimensional NumPy array (n_instances, n_columns, n_timepoints).\n\n    Parameters\n    ----------\n    X : pd.DataFrame\n        The multi-index pandas DataFrame\n\n    Returns\n    -------\n    X_3d : np.ndarray\n        3-dimensional NumPy array (n_instances, n_columns, n_timepoints)\n    """\n    if X.index.nlevels != 2:\n        raise ValueError("Multi-index DataFrame should have 2 levels.")\n\n    n_instances = len(X.index.get_level_values(0).unique())\n    n_timepoints = len(X.index.get_level_values(1).unique())\n    n_columns = X.shape[1]\n\n    X_3d = X.values.reshape(n_instances, n_timepoints, n_columns).swapaxes(1, 2)\n\n    return X_3d\n\n\ndef from_multi_index_to_3d_numpy_adp(obj, store=None):\n\n    res = from_multi_index_to_3d_numpy(X=obj)\n    if isinstance(store, dict):\n        store["columns"] = obj.columns\n\n    return res\n\n\nconvert_dict[("pd-multiindex", "numpy3D", "Panel")] = from_multi_index_to_3d_numpy_adp\n\n\ndef from_3d_numpy_to_multi_index(\n    X, instance_index=None, time_index=None, column_names=None\n):\n    """Convert 3D numpy Panel to pandas multi-index Panel.\n\n    Convert 3-dimensional NumPy array (n_instances, n_columns, n_timepoints)\n    to panel data stored as pandas multi-indexed DataFrame.\n\n    Parameters\n    ----------\n    X : np.ndarray\n        3-dimensional NumPy array (n_instances, n_columns, n_timepoints)\n\n    instance_index : str\n        Name of the multi-index level corresponding to the DataFrame\'s instances\n\n    time_index : str\n        Name of multi-index level corresponding to DataFrame\'s timepoints\n\n\n    Returns\n    -------\n    X_mi : pd.DataFrame\n        The multi-indexed pandas DataFrame\n    """\n    if X.ndim != 3:\n        msg = " ".join(\n            [\n                "Input should be 3-dimensional NumPy array with shape",\n                "(n_instances, n_columns, n_timepoints).",\n            ]\n        )\n        raise TypeError(msg)\n\n    n_instances, n_columns, n_timepoints = X.shape\n    multi_index = pd.MultiIndex.from_product(\n        [range(n_instances), range(n_columns), range(n_timepoints)],\n        names=["instances", "columns", "timepoints"],\n    )\n\n    X_mi = pd.DataFrame({"X": X.flatten()}, index=multi_index)\n    X_mi = X_mi.unstack(level="columns")\n\n    # Assign column names\n    if column_names is None:\n        X_mi.columns = _make_column_names(n_columns)\n\n    else:\n        X_mi.columns = column_names\n\n    index_rename_dict = {}\n    if instance_index is not None:\n        index_rename_dict["instances"] = instance_index\n\n    if time_index is not None:\n        index_rename_dict["timepoints"] = time_index\n\n    if len(index_rename_dict) > 0:\n        X_mi = X_mi.rename_axis(index=index_rename_dict)\n\n    return X_mi\n\n\ndef from_3d_numpy_to_multi_index_adp(obj, store=None):\n    res = from_3d_numpy_to_multi_index(X=obj)\n    if (\n        isinstance(store, dict)\n        and "columns" in store.keys()\n        and len(store["columns"]) == obj.shape[1]\n    ):\n        res.columns = store["columns"]\n    return res\n\n\nconvert_dict[("numpy3D", "pd-multiindex", "Panel")] = from_3d_numpy_to_multi_index_adp\n\n\ndef from_multi_index_to_nested(\n    multi_ind_dataframe, instance_index=None, cells_as_numpy=False\n):\n    """Convert a pandas DataFrame witha multi-index to a nested DataFrame.\n\n    Parameters\n    ----------\n    multi_ind_dataframe : pd.DataFrame\n        Input multi-indexed pandas DataFrame\n\n    instance_index_name : str\n        The name of multi-index level corresponding to the DataFrame\'s instances\n\n    cells_as_numpy : bool, default = False\n        If True, then nested cells contain NumPy array\n        If False, then nested cells contain pandas Series\n\n    Returns\n    -------\n    x_nested : pd.DataFrame\n        The nested version of the DataFrame\n    """\n    if instance_index is None:\n        instance_index = 0\n\n    # get number of distinct cases (note: a case may have 1 or many dimensions)\n    instance_idxs = multi_ind_dataframe.index.get_level_values(instance_index).unique()\n\n    x_nested = pd.DataFrame()\n\n    # Loop the dimensions (columns) of multi-index DataFrame\n    for _label, _series in multi_ind_dataframe.iteritems():  # noqa\n        # for _label in multi_ind_dataframe.columns:\n        #    _series = multi_ind_dataframe.loc[:, _label]\n        # Slice along the instance dimension to return list of series for each case\n        # Note: if you omit .rename_axis the returned DataFrame\n        #       prints time axis dimension at the start of each cell,\n        #       but this doesn\'t affect the values.\n        if cells_as_numpy:\n            dim_list = [\n                _series.xs(instance_idx, level=instance_index).values\n                for instance_idx in instance_idxs\n            ]\n        else:\n            dim_list = [\n                _series.xs(instance_idx, level=instance_index).rename_axis(None)\n                for instance_idx in instance_idxs\n            ]\n\n        x_nested[_label] = pd.Series(dim_list)\n    x_nested = pd.DataFrame(x_nested).set_axis(instance_idxs)\n\n    col_msg = "Multi-index and nested DataFrames should have same columns names"\n    assert (x_nested.columns == multi_ind_dataframe.columns).all(), col_msg\n\n    return x_nested\n\n\ndef from_multi_index_to_nested_adp(obj, store=None):\n\n    return from_multi_index_to_nested(multi_ind_dataframe=obj, instance_index=None)\n\n\nconvert_dict[("pd-multiindex", "nested_univ", "Panel")] = from_multi_index_to_nested_adp\n\n\ndef from_nested_to_multi_index(X, instance_index=None, time_index=None):\n    """Convert nested pandas Panel to multi-index pandas Panel.\n\n    Converts nested pandas DataFrame (with time series as pandas Series\n    or NumPy array in cells) into multi-indexed pandas DataFrame.\n\n    Can convert mixed nested and primitive DataFrame to multi-index DataFrame.\n\n    Parameters\n    ----------\n    X : pd.DataFrame\n        The nested DataFrame to convert to a multi-indexed pandas DataFrame\n\n    instance_index : str\n        Name of the multi-index level corresponding to the DataFrame\'s instances\n\n    time_index : str\n        Name of multi-index level corresponding to DataFrame\'s timepoints\n\n    Returns\n    -------\n    X_mi : pd.DataFrame\n        The multi-indexed pandas DataFrame\n\n    """\n    if time_index is None:\n        time_index_name = "timepoints"\n    else:\n        time_index_name = time_index\n\n    # n_columns = X.shape[1]\n    nested_col_mask = [*are_columns_nested(X)]\n\n    if instance_index is None:\n        instance_idxs = X.index.get_level_values(-1).unique()\n        # n_instances = instance_idxs.shape[0]\n        instance_index_name = "instance"\n\n    else:\n        if instance_index in X.index.names:\n            instance_idxs = X.index.get_level_values(instance_index).unique()\n        else:\n            instance_idxs = X.index.get_level_values(-1).unique()\n        # n_instances = instance_idxs.shape[0]\n        instance_index_name = instance_index\n\n    instances = []\n    for instance_idx in instance_idxs:\n        iidx = instance_idx\n        series = [i[1] for i in X.loc[iidx, :].iteritems()]\n        colnames = [i[0] for i in X.loc[iidx, :].iteritems()]\n        for x in series:\n            if hasattr(x, "name"):\n                x.name = None\n\n        instance = [pd.DataFrame(s, columns=[c]) for s, c in zip(series, colnames)]\n        instance = pd.concat(instance, axis=1)\n        # For primitive (non-nested column) assume the same\n        # primitive value applies to every timepoint of the instance\n        for col_idx, is_nested in enumerate(nested_col_mask):\n            if not is_nested:\n                instance.iloc[:, col_idx] = instance.iloc[:, col_idx].ffill()\n\n        # Correctly assign multi-index\n        multi_index = pd.MultiIndex.from_product(\n            [[instance_idx], instance.index],\n            names=[instance_index_name, time_index_name],\n        )\n        instance.index = multi_index\n        instances.append(instance)\n\n    X_mi = pd.concat(instances)\n    X_mi.columns = X.columns\n\n    return X_mi\n\n\ndef from_nested_to_multi_index_adp(obj, store=None):\n\n    return from_nested_to_multi_index(\n        X=obj, instance_index="instances", time_index="timepoints"\n    )\n\n\nconvert_dict[("nested_univ", "pd-multiindex", "Panel")] = from_nested_to_multi_index_adp\n\n\ndef _convert_series_cell_to_numpy(cell):\n    if isinstance(cell, pd.Series):\n        return cell.to_numpy()\n    else:\n        return cell\n\n\ndef from_nested_to_3d_numpy(X):\n    """Convert nested Panel to 3D numpy Panel.\n\n    Convert nested pandas DataFrame (with time series as pandas Series\n    in cells) into NumPy ndarray with shape\n    (n_instances, n_columns, n_timepoints).\n\n    Parameters\n    ----------\n    X : pd.DataFrame\n        Nested pandas DataFrame\n\n    Returns\n    -------\n    X_3d : np.ndarrray\n        3-dimensional NumPy array\n    """\n    # n_columns = X.shape[1]\n    nested_col_mask = [*are_columns_nested(X)]\n\n    # If all the columns are nested in structure\n    if nested_col_mask.count(True) == len(nested_col_mask):\n        X_3d = np.stack(\n            X.applymap(_convert_series_cell_to_numpy)\n            .apply(lambda row: np.stack(row), axis=1)\n            .to_numpy()\n        )\n\n    # If some columns are primitive (non-nested) then first convert to\n    # multi-indexed DataFrame where the same value of these columns is\n    # repeated for each timepoint\n    # Then the multi-indexed DataFrame can be converted to 3d NumPy array\n    else:\n        X_mi = from_nested_to_multi_index(X)\n        X_3d = from_multi_index_to_3d_numpy(\n            X_mi, instance_index="instance", time_index="timepoints"\n        )\n\n    return X_3d\n\n\ndef from_nested_to_3d_numpy_adp(obj, store=None):\n\n    return from_nested_to_3d_numpy(X=obj)\n\n\nconvert_dict[("nested_univ", "numpy3D", "Panel")] = from_nested_to_3d_numpy_adp\n\n\ndef from_3d_numpy_to_nested(X, column_names=None, cells_as_numpy=False):\n    """Convert numpy 3D Panel to nested pandas Panel.\n\n    Convert NumPy ndarray with shape (n_instances, n_columns, n_timepoints)\n    into nested pandas DataFrame (with time series as pandas Series in cells)\n\n    Parameters\n    ----------\n    X : np.ndarray\n        3-dimensional Numpy array to convert to nested pandas DataFrame format\n\n    column_names: list-like, default = None\n        Optional list of names to use for naming nested DataFrame\'s columns\n\n    cells_as_numpy : bool, default = False\n        If True, then nested cells contain NumPy array\n        If False, then nested cells contain pandas Series\n\n\n    Returns\n    -------\n    df : pd.DataFrame\n    """\n    df = pd.DataFrame()\n    # n_instances, n_variables, _ = X.shape\n    n_instances, n_columns, n_timepoints = X.shape\n\n    container = np.array if cells_as_numpy else pd.Series\n\n    if column_names is None:\n        column_names = _make_column_names(n_columns)\n\n    else:\n        if len(column_names) != n_columns:\n            msg = " ".join(\n                [\n                    f"Input 3d Numpy array as {n_columns} columns,",\n                    f"but only {len(column_names)} names supplied",\n                ]\n            )\n            raise ValueError(msg)\n\n    for j, column in enumerate(column_names):\n        df[column] = [container(X[instance, j, :]) for instance in range(n_instances)]\n    return df\n\n\ndef from_3d_numpy_to_nested_adp(obj, store=None):\n\n    return from_3d_numpy_to_nested(X=obj)\n\n\nconvert_dict[("numpy3D", "nested_univ", "Panel")] = from_3d_numpy_to_nested_adp\n\n\ndef from_dflist_to_multiindex(obj, store=None):\n\n    n = len(obj)\n\n    mi = pd.concat(obj, axis=0, keys=range(n), names=["instances", "timepoints"])\n\n    return mi\n\n\nconvert_dict[("df-list", "pd-multiindex", "Panel")] = from_dflist_to_multiindex\n\n\ndef from_multiindex_to_dflist(obj, store=None):\n\n    instance_index = obj.index.levels[0]\n\n    Xlist = [obj.loc[i].rename_axis(None) for i in instance_index]\n\n    return Xlist\n\n\nconvert_dict[("pd-multiindex", "df-list", "Panel")] = from_multiindex_to_dflist\n\n\ndef from_dflist_to_numpy3D(obj, store=None):\n\n    if not isinstance(obj, list):\n        raise TypeError("obj must be a list of pd.DataFrame")\n\n    n = len(obj[0])\n    cols = set(obj[0].columns)\n\n    for i in range(len(obj)):\n        if not n == len(obj[i]) or not set(obj[i].columns) == cols:\n            raise ValueError("elements of obj must have same length and columns")\n\n    nparr = np.array([X.to_numpy().transpose() for X in obj])\n\n    return nparr\n\n\nconvert_dict[("df-list", "numpy3D", "Panel")] = from_dflist_to_numpy3D\n\n\ndef from_numpy3d_to_dflist(obj, store=None):\n\n    if not isinstance(obj, np.ndarray) or len(obj.shape) != 3:\n        raise TypeError("obj must be a 3D numpy.ndarray")\n\n    cols = _make_column_names(obj.shape[1])\n    Xlist = [pd.DataFrame(obj[i].T, columns=cols) for i in range(len(obj))]\n\n    return Xlist\n\n\nconvert_dict[("numpy3D", "df-list", "Panel")] = from_numpy3d_to_dflist\n\n\ndef from_nested_to_df_list_adp(obj, store=None):\n\n    # this is not already implemented, so chain two conversions\n    obj = from_nested_to_multi_index_adp(obj, store=store)\n    return from_multiindex_to_dflist(obj, store=store)\n\n\nconvert_dict[("nested_univ", "df-list", "Panel")] = from_nested_to_df_list_adp\n\n\ndef from_df_list_to_nested_adp(obj, store=None):\n\n    # this is not already implemented, so chain two conversions\n    obj = from_dflist_to_multiindex(obj, store=store)\n    return from_multi_index_to_nested_adp(obj, store=store)\n\n\nconvert_dict[("df-list", "nested_univ", "Panel")] = from_df_list_to_nested_adp\n\n\ndef from_numpy3d_to_numpyflat(obj, store=None):\n\n    if not isinstance(obj, np.ndarray) or len(obj.shape) != 3:\n        raise TypeError("obj must be a 3D numpy.ndarray")\n\n    shape = obj.shape\n\n    # store second dimension shape/length if we want to restore\n    if isinstance(store, dict):\n        store["numpy_second_dim"] = shape[1]\n\n    obj_in_2D = obj.reshape(shape[0], shape[1] * shape[2])\n\n    return obj_in_2D\n\n\nconvert_dict[("numpy3D", "numpyflat", "Panel")] = from_numpy3d_to_numpyflat\n\n\ndef from_numpyflat_to_numpy3d(obj, store=None):\n\n    if not isinstance(obj, np.ndarray) or len(obj.shape) != 2:\n        raise TypeError("obj must be a 2D numpy.ndarray")\n\n    shape = obj.shape\n\n    # if store has old 2nd dimension, try to restore, otherwise assume 1\n    if (\n        isinstance(store, dict)\n        and "numpy_second_dim" in store.keys()\n        and isinstance(store["numpy_second_dim"], int)\n        and shape[1] % store["numpy_second_dim"] == 0\n    ):\n        shape_1 = store["numpy_second_dim"]\n        target_shape = (shape[0], shape_1, shape[1] / shape_1)\n    else:\n        target_shape = (shape[0], 1, shape[1])\n\n    obj_in_3D = obj.reshape(target_shape)\n\n    return obj_in_3D\n\n\nconvert_dict[("numpyflat", "numpy3D", "Panel")] = from_numpyflat_to_numpy3d\n\n\n# obtain other conversions from/to numpyflat via concatenation to numpy3D\ndef _concat(fun1, fun2):\n    def concat_fun(obj, store=None):\n        obj1 = fun1(obj, store=store)\n        obj2 = fun2(obj1, store=store)\n        return obj2\n\n    return concat_fun\n\n\nfor tp in set(MTYPE_LIST_PANEL).difference(["numpyflat", "numpy3D"]):\n    if ("numpy3D", tp, "Panel") in convert_dict.keys():\n        if ("numpyflat", tp, "Panel") not in convert_dict.keys():\n            convert_dict[("numpyflat", tp, "Panel")] = _concat(\n                convert_dict[("numpyflat", "numpy3D", "Panel")],\n                convert_dict[("numpy3D", tp, "Panel")],\n            )\n    if (tp, "numpy3D", "Panel") in convert_dict.keys():\n        if (tp, "numpyflat", "Panel") not in convert_dict.keys():\n            convert_dict[(tp, "numpyflat", "Panel")] = _concat(\n                convert_dict[(tp, "numpy3D", "Panel")],\n                convert_dict[("numpy3D", "numpyflat", "Panel")],\n            )\n',
            'sktime/datatypes/_series/_convert.py': '# -*- coding: utf-8 -*-\n"""Machine type converters for Series scitype.\n\nExports conversion and mtype dictionary for Series scitype:\n\nconvert_dict: dict indexed by triples of str\n  1st element = convert from - str\n  2nd element = convert to - str\n  3rd element = considered as this scitype - str\nelements are conversion functions of machine type (1st) -> 2nd\n\nFunction signature of all elements\nconvert_dict[(from_type, to_type, as_scitype)]\n\nParameters\n----------\nobj : from_type - object to convert\nstore : dictionary - reference of storage for lossy conversions, default=None (no store)\n\nReturns\n-------\nconverted_obj : to_type - object obj converted to to_type\n\nRaises\n------\nValueError and TypeError, if requested conversion is not possible\n                            (depending on conversion logic)\n"""\n\n__author__ = ["fkiraly"]\n\n__all__ = ["convert_dict"]\n\nimport numpy as np\nimport pandas as pd\n\n##############################################################\n# methods to convert one machine type to another machine type\n##############################################################\n\nconvert_dict = dict()\n\n\ndef convert_identity(obj, store=None):\n\n    return obj\n\n\n# assign identity function to type conversion to self\nfor tp in ["pd.Series", "pd.DataFrame", "np.ndarray"]:\n    convert_dict[(tp, tp, "Series")] = convert_identity\n\n\ndef convert_UvS_to_MvS_as_Series(obj: pd.Series, store=None) -> pd.DataFrame:\n\n    if not isinstance(obj, pd.Series):\n        raise TypeError("input must be a pd.Series")\n\n    res = pd.DataFrame(obj)\n\n    if (\n        isinstance(store, dict)\n        and "columns" in store.keys()\n        and len(store["columns"]) == 1\n    ):\n        res.columns = store["columns"]\n\n    return res\n\n\nconvert_dict[("pd.Series", "pd.DataFrame", "Series")] = convert_UvS_to_MvS_as_Series\n\n\ndef convert_MvS_to_UvS_as_Series(obj: pd.DataFrame, store=None) -> pd.Series:\n\n    if not isinstance(obj, pd.DataFrame):\n        raise TypeError("input is not a pd.DataFrame")\n\n    if len(obj.columns) != 1:\n        raise ValueError("input must be univariate pd.DataFrame, with one column")\n\n    if isinstance(store, dict):\n        store["columns"] = obj.columns[[0]]\n\n    y = obj[obj.columns[0]]\n    y.name = None\n\n    return y\n\n\nconvert_dict[("pd.DataFrame", "pd.Series", "Series")] = convert_MvS_to_UvS_as_Series\n\n\ndef convert_MvS_to_np_as_Series(obj: pd.DataFrame, store=None) -> np.ndarray:\n\n    if not isinstance(obj, pd.DataFrame):\n        raise TypeError("input must be a pd.DataFrame")\n\n    if isinstance(store, dict):\n        store["columns"] = obj.columns\n        store["index"] = obj.index\n\n    return obj.to_numpy()\n\n\nconvert_dict[("pd.DataFrame", "np.ndarray", "Series")] = convert_MvS_to_np_as_Series\n\n\ndef convert_UvS_to_np_as_Series(obj: pd.Series, store=None) -> np.ndarray:\n\n    if not isinstance(obj, pd.Series):\n        raise TypeError("input must be a pd.Series")\n\n    if isinstance(store, dict):\n        store["index"] = obj.index\n\n    return pd.DataFrame(obj).to_numpy()\n\n\nconvert_dict[("pd.Series", "np.ndarray", "Series")] = convert_UvS_to_np_as_Series\n\n\ndef convert_np_to_MvS_as_Series(obj: np.ndarray, store=None) -> pd.DataFrame:\n\n    if not isinstance(obj, np.ndarray) and len(obj.shape) > 2:\n        raise TypeError("input must be a np.ndarray of dim 1 or 2")\n\n    if len(obj.shape) == 1:\n        obj = np.reshape(obj, (-1, 1))\n\n    res = pd.DataFrame(obj)\n\n    # add column names or index from store if stored and length fits\n    if (\n        isinstance(store, dict)\n        and "columns" in store.keys()\n        and len(store["columns"]) == obj.shape[1]\n    ):\n        res.columns = store["columns"]\n    if (\n        isinstance(store, dict)\n        and "index" in store.keys()\n        and len(store["index"]) == obj.shape[0]\n    ):\n        res.index = store["index"]\n\n    return res\n\n\nconvert_dict[("np.ndarray", "pd.DataFrame", "Series")] = convert_np_to_MvS_as_Series\n\n\ndef convert_np_to_UvS_as_Series(obj: np.ndarray, store=None) -> pd.Series:\n\n    if not isinstance(obj, np.ndarray) or obj.ndim > 2:\n        raise TypeError("input must be a one-column np.ndarray of dim 1 or 2")\n\n    if obj.ndim == 2 and obj.shape[1] != 1:\n        raise TypeError("input must be a one-column np.ndarray of dim 1 or 2")\n\n    res = pd.Series(obj.flatten())\n\n    # add index from store if stored and length fits\n    if (\n        isinstance(store, dict)\n        and "index" in store.keys()\n        and len(store["index"]) == obj.shape[0]\n    ):\n        res.index = store["index"]\n\n    return res\n\n\nconvert_dict[("np.ndarray", "pd.Series", "Series")] = convert_np_to_UvS_as_Series\n',
            'sktime/transformations/panel/segment.py': '# -*- coding: utf-8 -*-\n"""Interval and window segmenter transformers."""\nimport math\n\nimport numpy as np\nimport pandas as pd\nfrom sklearn.utils import check_random_state\n\nfrom sktime.datatypes._panel._convert import (\n    _concat_nested_arrays,\n    _get_column_names,\n    _get_time_index,\n)\nfrom sktime.transformations.base import BaseTransformer\nfrom sktime.utils.validation import check_window_length\nfrom sktime.utils.validation.panel import check_X\n\n\nclass IntervalSegmenter(BaseTransformer):\n    """Interval segmentation transformer.\n\n    Parameters\n    ----------\n    intervals : int, np.ndarray or list of np.ndarrays with one for each\n    column of input data.\n        Intervals to generate.\n        - If int, intervals gives the number of generated intervals.\n        - If ndarray, 2d np.ndarray [n_intervals, 2] with rows giving\n        intervals, the first column giving start points,\n        and the second column giving end points of intervals\n    """\n\n    _tags = {\n        "univariate-only": True,\n        "scitype:transform-input": "Series",\n        # what is the scitype of X: Series, or Panel\n        "scitype:transform-output": "Series",\n        # what scitype is returned: Primitives, Series, Panel\n        "scitype:instancewise": True,  # is this an instance-wise transform?\n        "X_inner_mtype": "nested_univ",  # which mtypes do _fit/_predict support for X?\n        "y_inner_mtype": "None",  # which mtypes do _fit/_predict support for X?\n        "fit_is_empty": False,  # is fit empty and can be skipped? Yes = True\n        "capability:unequal_length:removes": True,\n        # is transform result always guaranteed to be equal length (and series)?\n    }\n\n    def __init__(self, intervals=10):\n        self.intervals = intervals\n        self._time_index = []\n        self.input_shape_ = ()\n        super(IntervalSegmenter, self).__init__()\n\n    def _fit(self, X, y=None):\n        """\n        Fit transformer, generating random interval indices.\n\n        Parameters\n        ----------\n        X : nested pandas DataFrame of shape [n_instances, n_features]\n            each cell of X must contain pandas.Series\n            Data to fit transform to\n        y : ignored argument for interface compatibility\n            Additional data, e.g., labels for transformation\n\n        Returns\n        -------\n        self : an instance of self.\n        """\n        X = check_X(X, enforce_univariate=True, coerce_to_numpy=True)\n\n        n_instances, n_columns, n_timepoints = X.shape\n        self.input_shape_ = n_instances, n_columns, n_timepoints\n\n        self._time_index = np.arange(n_timepoints)\n\n        if isinstance(self.intervals, np.ndarray):\n            self.intervals_ = list(self.intervals)\n\n        elif isinstance(self.intervals, (int, np.integer)):\n            if not self.intervals <= n_timepoints // 2:\n                raise ValueError(\n                    "The number of intervals must be half the number of time points"\n                    " or less"\n                )\n            self.intervals_ = np.array_split(self._time_index, self.intervals)\n\n        else:\n            raise ValueError(\n                f"Intervals must be either an integer, an array with "\n                f"start and end points, but found: {self.intervals}"\n            )\n        return self\n\n    def _transform(self, X, y=None):\n        """Transform input series.\n\n        Transform X, segments time-series in each column into random\n        intervals using interval indices generated\n        during `fit`.\n\n        Parameters\n        ----------\n        X : nested pandas DataFrame of shape [n_instances, n_features]\n            each cell of X must contain pandas.Series\n            Data to be transformed\n        y : ignored argument for interface compatibility\n\n        Returns\n        -------\n        Xt : pandas DataFrame\n          Transformed pandas DataFrame with same number of rows and one\n          column for each generated interval.\n        """\n        # Tabularise assuming series\n        # have equal indexes in any given column\n        X = check_X(X, enforce_univariate=True, coerce_to_numpy=True)\n        X = X.squeeze(1)\n\n        # Segment into intervals.\n        # TODO generalise to non-equal-index cases\n        intervals = []\n\n        # univariate, only a single column name\n        column_names = _get_column_names(X)[0]\n        new_column_names = []\n        for interval in self.intervals_:\n            start, end = interval[0], interval[-1]\n            interval = X[:, start:end]\n            intervals.append(interval)\n            new_column_names.append(f"{column_names}_{start}_{end}")\n\n        # Return nested pandas DataFrame.\n        Xt = pd.DataFrame(_concat_nested_arrays(intervals))\n        Xt.columns = new_column_names\n        return Xt\n\n    @classmethod\n    def get_test_params(cls, parameter_set="default"):\n        """Return testing parameter settings for the estimator.\n\n        Parameters\n        ----------\n        parameter_set : str, default="default"\n            Name of the set of test parameters to return, for use in tests. If no\n            special parameters are defined for a value, will return `"default"` set.\n\n\n        Returns\n        -------\n        params : dict or list of dict, default = {}\n            Parameters to create testing instances of the class\n            Each dict are parameters to construct an "interesting" test instance, i.e.,\n            `MyClass(**params)` or `MyClass(**params[i])` creates a valid test instance.\n            `create_test_instance` uses the first (or only) dictionary in `params`\n        """\n        # small number of intervals for testing\n        params = {"intervals": 2}\n        return params\n\n\nclass RandomIntervalSegmenter(IntervalSegmenter):\n    """Random interval segmenter transformer.\n\n    Transformer that segments time-series into random intervals with\n    random starting points and lengths. Some\n    intervals may overlap and may be duplicates.\n\n    Parameters\n    ----------\n    n_intervals : str, int or float\n        Number of intervals to generate.\n        - If "log", log of m is used where m is length of time series.\n        - If "sqrt", sqrt of m is used.\n        - If "random", random number of intervals is generated.\n        - If int, n_intervals intervals are generated.\n        - If float, int(n_intervals * m) is used with n_intervals giving the\n        fraction of intervals of the\n        time series length.\n\n        For all arguments relative to the length of the time series,\n        the generated number of intervals is\n        always at least 1.\n\n        Default is "sqrt".\n\n    random_state : int, RandomState instance or None, optional (default=None)\n        If int, random_state is the seed used by the random number generator;\n        If RandomState instance, random_state is the random number generator;\n        If None, the random number generator is the RandomState instance used\n        by `np.random`.\n    """\n\n    _tags = {\n        "X_inner_mtype": "nested_univ",  # which mtypes do _fit/_predict support for X?\n        "y_inner_mtype": "pd_Series_Table",\n        # which mtypes do _fit/_predict support for y?\n    }\n\n    def __init__(\n        self, n_intervals="sqrt", min_length=None, max_length=None, random_state=None\n    ):\n        self.n_intervals = n_intervals\n        self.min_length = min_length\n        self.max_length = max_length\n        self.random_state = random_state\n        super(RandomIntervalSegmenter, self).__init__()\n\n    def _fit(self, X, y=None):\n        """Fit transformer, generating random interval indices.\n\n        Parameters\n        ----------\n        X : nested pandas DataFrame of shape [n_instances, n_features]\n            each cell of X must contain pandas.Series\n            Data to fit transform to\n        y : any container with method shape, optional, default=None\n            y.shape[0] determines n_timepoints, 1 if None\n\n        Returns\n        -------\n        self : RandomIntervalSegmenter\n            This estimator\n        """\n        if y is not None:\n            n_timepoints = y.shape[0]\n        else:\n            n_timepoints = 1\n\n        self.min_length = check_window_length(\n            self.min_length, n_timepoints, "min_length"\n        )\n        self.max_length = check_window_length(\n            self.max_length, n_timepoints, "max_length"\n        )\n        if self.min_length is None:\n            min_length = 2\n        else:\n            min_length = self.min_length\n        if self.max_length is not None:\n            if not min_length < self.max_length:\n                raise ValueError("`max_length` must be bigger than `min_length`.")\n\n        self.input_shape_ = X.shape\n\n        # Retrieve time-series indexes from each column.\n        # TODO generalise to columns with series of unequal length\n        self._time_index = _get_time_index(X)\n\n        # Compute random intervals for each column.\n        # TODO if multiple columns are passed, introduce option to compute\n        #  one set of shared intervals,\n        #  or rely on ColumnTransformer?\n        if self.n_intervals == "random":\n            if self.min_length is not None or self.max_length is not None:\n                raise ValueError(\n                    "Setting `min_length` or `max_length` is not yet "\n                    "implemented for `n_intervals=\'random\'`."\n                )\n            self.intervals_ = _rand_intervals_rand_n(\n                self._time_index, random_state=self.random_state\n            )\n        else:\n            self.intervals_ = _rand_intervals_fixed_n(\n                self._time_index,\n                n_intervals=self.n_intervals,\n                min_length=min_length,\n                max_length=self.max_length,\n                random_state=self.random_state,\n            )\n        return self\n\n    @classmethod\n    def get_test_params(cls, parameter_set="default"):\n        """Return testing parameter settings for the estimator.\n\n        Parameters\n        ----------\n        parameter_set : str, default="default"\n            Name of the set of test parameters to return, for use in tests. If no\n            special parameters are defined for a value, will return `"default"` set.\n\n\n        Returns\n        -------\n        params : dict or list of dict, default = {}\n            Parameters to create testing instances of the class\n            Each dict are parameters to construct an "interesting" test instance, i.e.,\n            `MyClass(**params)` or `MyClass(**params[i])` creates a valid test instance.\n            `create_test_instance` uses the first (or only) dictionary in `params`\n        """\n        # we need to override this, or it inherits from IntervalSegmenter\n        #   but this estimator does not have an "intervals" parameter\n        return {}\n\n\ndef _rand_intervals_rand_n(x, random_state=None):\n    """Sample a random number of intervals.\n\n    Compute a random number of intervals from index (x) with\n    random starting points and lengths. Intervals are unique, but may\n    overlap.\n\n    Parameters\n    ----------\n    x : array_like, shape = (n_timepoints,)\n\n    Returns\n    -------\n    intervals : array-like, shape = (n_intervals, 2)\n        2d array containing start and end points of intervals\n\n    References\n    ----------\n    ..[1] Deng, Houtao, et al. "A time series forest for classification\n    and feature extraction."\n        Information Sciences 239 (2013): 142-153.\n    """\n    rng = check_random_state(random_state)\n    starts = []\n    ends = []\n    n_timepoints = x.shape[0]  # series length\n    W = rng.randint(1, n_timepoints, size=int(np.sqrt(n_timepoints)))\n    for w in W:\n        size = n_timepoints - w + 1\n        start = rng.randint(size, size=int(np.sqrt(size)))\n        starts.extend(start)\n        for s in start:\n            end = s + w\n            ends.append(end)\n    return np.column_stack([starts, ends])\n\n\ndef _rand_intervals_fixed_n(\n    x, n_intervals, min_length=1, max_length=None, random_state=None\n):\n    """Sample a fixed number of intervals.\n\n    Compute a fixed number (n) of intervals from index (x) with\n    random starting points and lengths. Intervals may overlap and may\n    not be unique.\n\n    Parameters\n    ----------\n    x : array_like, shape = (n_timepoints,)\n        Array containing the time-series index.\n    n_intervals : \'sqrt\', \'log\', float or int\n\n    Returns\n    -------\n    intervals : array-like, shape = (n_intervals, 2)\n        2d array containing start and end points of intervals\n    """\n    rng = check_random_state(random_state)\n    n_timepoints = x.shape[0]\n    n_intervals = _get_n_from_n_timepoints(n_timepoints, n_intervals)\n    starts = rng.randint(0, n_timepoints - min_length + 1, size=(n_intervals,))\n    if max_length is None:\n        max_length = n_timepoints - starts\n    ends = rng.randint(starts + min_length, starts + max_length + 1)\n    return np.column_stack([starts, ends])\n\n\nclass SlidingWindowSegmenter(BaseTransformer):\n    """Sliding window segmenter transformer.\n\n    This class is to transform a univariate series into a\n    multivariate one by extracting sets of subsequences.\n    It does this by firstly padding the time series on either end\n    floor(window_length/2) times. Then it performs a sliding\n    window of size window_length and hop size 1.\n\n    e.g. if window_length = 3\n\n    S = 1,2,3,4,5, floor(3/2) = 1 so S would be padded as\n\n    1,1,2,3,4,5,5\n\n    then SlidingWindowSegmenter would extract the following:\n\n    (1,1,2),(1,2,3),(2,3,4),(3,4,5),(4,5,5)\n\n    the time series is now a multivariate one.\n\n    Parameters\n    ----------\n        window_length : int, length of interval.\n\n    Returns\n    -------\n        df : pandas dataframe of shape\n             [n_instances, n_timepoints]\n\n    Proposed in the ShapeDTW algorithm.\n    """\n\n    _tags = {\n        "univariate-only": True,\n        "fit_is_empty": True,\n        "scitype:transform-input": "Series",\n        # what is the scitype of X: Series, or Panel\n        "scitype:transform-output": "Series",\n        # what scitype is returned: Primitives, Series, Panel\n        "scitype:instancewise": False,  # is this an instance-wise transform?\n        "X_inner_mtype": "nested_univ",  # which mtypes do _fit/_predict support for X?\n        "y_inner_mtype": "None",  # which mtypes do _fit/_predict support for y?\n    }\n\n    def __init__(self, window_length=5):\n        self.window_length = window_length\n        super(SlidingWindowSegmenter, self).__init__()\n\n    def _transform(self, X, y=None):\n        """Transform time series.\n\n        Parameters\n        ----------\n        X : nested pandas DataFrame of shape [n_instances, n_features]\n            each cell of X must contain pandas.Series\n            Data to be transformed\n        y : ignored argument for interface compatibility\n\n        Returns\n        -------\n        dims: a pandas data frame of shape = [n_instances, n_timepoints]\n        """\n        # get the number of attributes and instances\n        X = check_X(X, enforce_univariate=True, coerce_to_numpy=True)\n        X = X.squeeze(1)\n\n        n_timepoints = X.shape[1]\n        n_instances = X.shape[0]\n\n        # Check the parameters are appropriate\n        self._check_parameters(n_timepoints)\n\n        pad_amnt = math.floor(self.window_length / 2)\n        padded_data = np.zeros((n_instances, n_timepoints + (2 * pad_amnt)))\n\n        # Pad both ends of X\n        for i in range(n_instances):\n            padded_data[i] = np.pad(X[i], pad_amnt, mode="edge")\n\n        subsequences = np.zeros((n_instances, n_timepoints, self.window_length))\n\n        # Extract subsequences\n        for i in range(n_instances):\n            subsequences[i] = self._extract_subsequences(padded_data[i], n_timepoints)\n\n        # Convert this into a panda\'s data frame\n        df = pd.DataFrame()\n        for i in range(len(subsequences)):\n            inst = subsequences[i]\n            data = []\n            for j in range(len(inst)):\n                data.append(pd.Series(inst[j]))\n            df[i] = data\n\n        return df.transpose()\n\n    def _extract_subsequences(self, instance, n_timepoints):\n        """Extract a set of subsequences from a list of instances.\n\n        Adopted from -\n        https://stackoverflow.com/questions/4923617/efficient-numpy-2d-array-\n        construction-from-1d-array/4924433#4924433\n\n        """\n        shape = (n_timepoints, self.window_length)\n        strides = (instance.itemsize, instance.itemsize)\n        return np.lib.stride_tricks.as_strided(instance, shape=shape, strides=strides)\n\n    def _check_parameters(self, n_timepoints):\n        """Check the values of parameters for interval segmenter.\n\n        Throws\n        ------\n        ValueError or TypeError if a parameters input is invalid.\n        """\n        if isinstance(self.window_length, int):\n            if self.window_length <= 0:\n                raise ValueError(\n                    "window_length must have the \\\n                                  value of at least 1"\n                )\n        else:\n            raise TypeError(\n                "window_length must be an \'int\'. \\\n                            Found \'"\n                + type(self.window_length).__name__\n                + "\' instead."\n            )\n\n\ndef _get_n_from_n_timepoints(n_timepoints, n="sqrt"):\n    """Get number of intervals from number of time points.\n\n    Helpful to compute number of intervals relative to time series length,\n    e.g. using floats or functions.\n\n    Parameters\n    ----------\n    n_timepoints : int\n    n : {int, float, str, callable}\n\n    Returns\n    -------\n    n_intervals_ : int\n        Computed number of intervals\n    """\n    # check input: n_timepoints\n    if not np.issubdtype(type(n_timepoints), np.dtype(int).type):\n        raise ValueError(\n            f"`n_timepoints` must be an integer, but found: " f"{type(n_timepoints)}"\n        )\n    if not n_timepoints >= 1:\n        raise ValueError(f"`n_timepoints` must be >= 1, but found: {n_timepoints}")\n\n    # compute number of splits\n    allowed_strings = ["sqrt", "log"]\n\n    # integer\n    if np.issubdtype(type(n), np.dtype(int).type):\n        if not n <= n_timepoints:\n            raise ValueError(\n                f"If `n_intervals` is an integer, it must be smaller "\n                f"than `n_timepoints`, but found:  `n_intervals`={n} "\n                f"and `n_timepoints`={n_timepoints}"\n            )\n        if n < 1:\n            raise ValueError(\n                f"If `n_intervals` is an integer, "\n                f"`n_intervals` must be >= 1, but found: {n}"\n            )\n        n_intervals_ = n\n\n    # function\n    elif callable(n):\n        n_intervals_ = n(n_timepoints)\n\n    # string\n    elif isinstance(n, str):\n        if n not in allowed_strings:\n            raise ValueError(\n                f"If `n_intervals` is a string, `n_intervals` must be "\n                f"in {allowed_strings}, but found: {n}"\n            )\n        str_func_map = {"sqrt": np.sqrt, "log": np.log}\n        func = str_func_map[n]\n        n_intervals_ = func(n_timepoints)\n\n    # float\n    elif isinstance(n, float):\n        if not (0 < n <= 1):\n            raise ValueError(\n                f"If `n_intervals` is a float, `n_intervals` must be > 0 "\n                f"and <= 1, but found: {n}"\n            )\n        n_intervals_ = n * n_timepoints\n\n    else:\n        raise ValueError(\n            f"`n_intervals` must be either one of the allowed string options "\n            f"in "\n            f"{allowed_strings}, an integer or a float number."\n        )\n\n    # make sure n_intervals is an integer and there is at least one interval\n    n_intervals_ = np.maximum(1, int(n_intervals_))\n    return n_intervals_\n',
            'sktime/transformations/panel/tests/test_segment.py': '# -*- coding: utf-8 -*-\nimport numpy as np\nimport pandas as pd\nimport pytest\n\nfrom sktime.transformations.panel.segment import RandomIntervalSegmenter\nfrom sktime.transformations.panel.segment import _rand_intervals_fixed_n\nfrom sktime.transformations.panel.segment import _rand_intervals_rand_n\nfrom sktime.utils._testing.panel import _make_nested_from_array\n\nN_ITER = 10\n\n\n# Test output format and dimensions.\n@pytest.mark.parametrize("n_instances", [1, 3])\n@pytest.mark.parametrize("n_timepoints", [10, 20])\n@pytest.mark.parametrize("n_intervals", [0.1, 1.0, 1, 3, 10, "sqrt", "random", "log"])\ndef test_output_format_dim(n_timepoints, n_instances, n_intervals):\n    X = _make_nested_from_array(\n        np.ones(n_timepoints), n_instances=n_instances, n_columns=1\n    )\n\n    trans = RandomIntervalSegmenter(n_intervals=n_intervals)\n    Xt = trans.fit_transform(X)\n\n    # Check number of rows and output type.\n    assert isinstance(Xt, pd.DataFrame)\n    assert Xt.shape[0] == X.shape[0]\n\n    # Check number of generated intervals/columns.\n    if n_intervals != "random":\n        if np.issubdtype(type(n_intervals), np.floating):\n            assert Xt.shape[1] == np.maximum(1, int(n_timepoints * n_intervals))\n        elif np.issubdtype(type(n_intervals), np.integer):\n            assert Xt.shape[1] == n_intervals\n        elif n_intervals == "sqrt":\n            assert Xt.shape[1] == np.maximum(1, int(np.sqrt(n_timepoints)))\n        elif n_intervals == "log":\n            assert Xt.shape[1] == np.maximum(1, int(np.log(n_timepoints)))\n\n\n# Check that exception is raised for bad input args.\n@pytest.mark.parametrize("bad_interval", [0, -0, "str", 1.2, -1.2, -1])\ndef test_bad_input_args(bad_interval):\n    X = _make_nested_from_array(np.ones(10), n_instances=10, n_columns=2)\n    with pytest.raises(ValueError):\n        RandomIntervalSegmenter(n_intervals=bad_interval).fit(X)\n\n\n# Helper function for checking generated intervals.\n@pytest.mark.parametrize(\n    "random_state", list(np.random.randint(100, size=10))\n)  # run repeatedly\n@pytest.mark.parametrize("n_intervals", ["sqrt", "log", 0.1, 1, 3])\ndef test_rand_intervals_fixed_n(random_state, n_intervals):\n    n_timepoints = 30\n    x = np.arange(n_timepoints)\n\n    intervals = _rand_intervals_fixed_n(x, n_intervals=n_intervals)\n    assert intervals.ndim == 2\n    assert np.issubdtype(intervals.dtype, np.integer)\n    # assert intervals.shape[0] == np.unique(intervals, axis=0).shape[0]  #\n    # no duplicates\n\n    starts = intervals[:, 0]\n    ends = intervals[:, 1]\n    assert np.all(ends <= n_timepoints)  # within bounds\n    assert np.all(starts >= 0)  # within bounds\n    assert np.all(ends > starts)  # only non-empty intervals\n\n\n@pytest.mark.parametrize(\n    "random_state", list(np.random.randint(100, size=10))\n)  # run repeatedly\ndef test_rand_intervals_rand_n(random_state):\n    n_timepoints = 30\n    x = np.arange(n_timepoints)\n\n    intervals = _rand_intervals_rand_n(x)\n    assert intervals.ndim == 2\n    assert np.issubdtype(intervals.dtype, np.integer)\n    # assert intervals.shape[0] == np.unique(intervals, axis=0).shape[0]  #\n    # no duplicates\n\n    starts = intervals[:, 0]\n    ends = intervals[:, 1]\n    assert np.all(ends <= x.size)  # within bounds\n    assert np.all(starts >= 0)  # within bounds\n    assert np.all(ends > starts)  # only non-empty intervals\n\n\n@pytest.mark.parametrize("min_length", [1, 3])\n@pytest.mark.parametrize("max_length", [4, 5])\n@pytest.mark.parametrize("n_intervals", ["sqrt", "log", 0.1, 1, 3])\ndef test_rand_intervals_fixed_n_min_max_length(n_intervals, min_length, max_length):\n    n_timepoints = 30\n    x = np.arange(n_timepoints)\n\n    intervals = _rand_intervals_fixed_n(\n        x, n_intervals=n_intervals, min_length=min_length, max_length=max_length\n    )\n    lengths = intervals[:, 1] - intervals[:, 0]  # length = end - start\n    assert np.all(lengths >= min_length)\n    assert np.all(lengths <= max_length)\n',
        }
